fn parse_rational(s: &str) -> f64 {
    if let Some((num, den)) = s.split_once('/') {
        let n = num.trim().parse::<f64>().unwrap_or(30.0);
        let d = den.trim().parse::<f64>().unwrap_or(1.0);
        if d == 0.0 { 30.0 } else { n / d }
